 88   // A power of 2.
 89   const ElementCount Start;
 90 
 91   // A power of 2. If End <= Start range is empty.
 92   ElementCount End;
 93 
 94   bool isEmpty() const {
 95     return End.getKnownMinValue() <= Start.getKnownMinValue();
 96   }
