1314                                           Old2NewTy &Old2New,
1315                                           InterleavedAccessInfo &IAI) {
1316   ReversePostOrderTraversal<VPBlockShallowTraversalWrapper<VPBlockBase *>>
1317       RPOT(Region->getEntry());
